mapper.update:
UPDATE HOSPITAL
SET MEDICAL_SUBJECTS =
(
SELECT LISTAGG(
MS.SUBJECT_NAME,
', '
) WITHIN GROUP (
ORDER BY MS.SUBJECT_NAME
)
FROM HOSPITAL_MEDICAL_SUBJECT HMS
JOIN MEDICAL_SUBJECT MS
ON HMS.SUBJECT_ID = MS.SUBJECT_ID
WHERE HMS.HOSPITAL_ID = #{hospitalId}
),
UPDATED_AT = SYSTIMESTAMP
WHERE HOSPITAL_ID = #{hospitalId}
